from enum import Enum
from dataclasses import dataclass
import re

class ModelTier(Enum):
    FAST_CHEAP = "gpt-3.5-turbo"        # ~$0.002/1K tokens
    BALANCED = "gpt-4o-mini"             # ~$0.015/1K tokens  
    POWERFUL = "gpt-4-turbo"             # ~$0.03/1K tokens

@dataclass
class RoutingDecision:
    model: str
    reason: str
    estimated_cost_multiplier: float

SIMPLE_TASK_PATTERNS = [
    r"\b(summarize|classify|extract|format|translate|yes or no)\b",
    r"\b(what is|define|list|name)\b",
]

COMPLEX_TASK_PATTERNS = [
    r"\b(reason|analyze|compare|evaluate|design|architect|debug|explain why)\b",
    r"\b(step by step|think through|pros and cons|trade-?offs)\b",
]

def route_to_model(task: str, context_tokens: int = 0) -> RoutingDecision:
    """Route a task to the appropriate model tier based on complexity."""
    task_lower = task.lower()
    task_length = len(task.split())

    # Check for explicit complexity signals
    is_complex = any(re.search(p, task_lower) for p in COMPLEX_TASK_PATTERNS)
    is_simple = any(re.search(p, task_lower) for p in SIMPLE_TASK_PATTERNS)

    # Long context always needs more capable model
    if context_tokens > 8000:
        return RoutingDecision(
            model=ModelTier.POWERFUL.value,
            reason="Large context window required",
            estimated_cost_multiplier=1.0
        )

    if is_complex or task_length > 100:
        return RoutingDecision(
            model=ModelTier.POWERFUL.value,
            reason="Complex reasoning task detected",
            estimated_cost_multiplier=1.0
        )
    elif is_simple or task_length < 20:
        return RoutingDecision(
            model=ModelTier.FAST_CHEAP.value,
            reason="Simple task — cheap model sufficient",
            estimated_cost_multiplier=0.07  # ~93% cost reduction
        )
    else:
        return RoutingDecision(
            model=ModelTier.BALANCED.value,
            reason="Moderate complexity — balanced model",
            estimated_cost_multiplier=0.5
        )

def cost_aware_completion(task: str, messages: list[dict]) -> dict:
    """Make an LLM call with automatic model routing."""
    context_tokens = sum(len(m["content"].split()) * 1.3 for m in messages)
    decision = route_to_model(task, int(context_tokens))

    print(f"Routing to {decision.model} ({decision.reason})")

    response = client.chat.completions.create(
        model=decision.model,
        messages=messages
    )
    return {
        "content": response.choices[0].message.content,
        "model_used": decision.model,
        "tokens_used": response.usage.total_tokens,
        "routing_reason": decision.reason
    }
